class Solution:
    def removeAlmostEqualCharacters(self, word: str) -> int:
        n = len(word)
        operations = 0
        i = 0
        while i < n - 1:
            # Check if current and next character are almost-equal
            if abs(ord(word[i]) - ord(word[i + 1])) <= 1:
                # Change the next character to a character that is not almost-equal
                operations += 1
                # Choose a character that is not almost-equal to current or next
                for c in "abcdefghijklmnopqrstuvwxyz":
                    if abs(ord(c) - ord(word[i])) > 1 and abs(ord(c) - ord(word[i + 1])) > 1:
                        word = word[:i + 1] + c + word[i + 2:]
                        break
                i += 2  # Skip the next character as it's now fixed
            else:
                i += 1
        return operations
